
-- -------------------------------------------------------- Tabel structuur voor tabel doelentabel-- --------------------------------------------------------DROP TABLE IF EXISTS doelentabel;CREATE TABLE doelentabel (doel_id smallint(11) NOT NULL auto_increment,persoon_id smallint(11) NOT NULL default '0',ontwen_fase varchar(10) default NULL,-- allemaal, vooronderzoek, afkick, start abstinentie, start controle, duurzame abstinentie, duurzame controle, heroverwegingdoel_niveau varchar(10) default NULL,-- zeker zeker twijfel redenatie smoes doel_categorie varchar(30) default NULL,doel_tekst varchar(80) default NULL,onderlig_doel varchar(80) default NULL,doel_gewicht_berek smallint(4) default NULL,doel_gewicht_zelf smallint(4) default NULL,doel_haalbaarh_zelf smallint(4) default NULL,PRIMARY KEY (doel_id),KEY persoon_id (persoon_id),KEY ontwen_fase (ontwen_fase)) TYPE=MyISAM AUTO_INCREMENT=100 ;-- Gegevens worden uitgevoerd voor tabel doelentabelINSERT INTO doelentabel VALUES (1,1,'allemaal','zeker','biologie','een zo gezond mogelijk functionerend lichaam','liefde','','','');INSERT INTO doelentabel VALUES (40,1,'allemaal','smoes','zelf','mijn ouders straffen','woede','','','');INSERT INTO doelentabel VALUES (50,1,'allemaal','smoes','zelf','hebbik toch schijt an','woede','','','');INSERT INTO doelentabel VALUES (90,1,'allemaal','smoes','sociaal','ik moet mijn gasten toch op een goede manier ontvangen','submissie','','','');